using UnityEngine;

/// <summary>
/// Golpe pesado como HABILIDADE (Urso Polar — o ataque normal dele são as
/// garras/ataque básico; o botão de habilidade dá o golpe pesado que quebra
/// gelo frágil e objectos). Reutiliza PlayerAttack.PerformStrike com dano
/// reforçado e cooldown próprio.
///
/// Activado via PrimaryAbility.HeavyStrike (AbilityRouter → TryStrike).
/// </summary>
[RequireComponent(typeof(PlayerAttack))]
public class HeavyStrikeAbility : MonoBehaviour, IFormAbility, IAbility, IActiveAbility
{
    [Header("Golpe Pesado")]
    [Tooltip("Dano extra somado ao attackDamage da forma.")]
    public int bonusDamage = 2;

    [Tooltip("Multiplicador do alcance em relação a attackRange da forma.")]
    public float rangeMultiplier = 1.2f;

    [Tooltip("Multiplicador do knockback em relação a attackKnockback da forma.")]
    public float knockbackMultiplier = 1.5f;

    [Tooltip("Cooldown próprio do golpe pesado (mais lento que o ataque básico).")]
    public float strikeCooldown = 1.2f;

    private PlayerAttack attack;
    private AnimalFormData form;
    private bool enabledForForm;
    private float cooldownTimer;

    private void Awake()
    {
        attack = GetComponent<PlayerAttack>();
    }

    private void Update()
    {
        if (cooldownTimer > 0f) cooldownTimer -= Time.deltaTime;
    }

    public void ConfigureFromForm(AnimalFormData newForm)
    {
        form = newForm;
        enabledForForm = form != null && form.primaryAbility == PrimaryAbility.HeavyStrike;
        cooldownTimer = 0f;
    }

    /// <summary>Executa o golpe pesado (AbilityRouter — PrimaryAbility.HeavyStrike).</summary>
    public void TryStrike()
    {
        if (!enabledForForm || cooldownTimer > 0f || form == null) return;

        cooldownTimer = strikeCooldown;

        attack.PerformStrike(
            form.attackDamage + bonusDamage,
            form.attackRange * rangeMultiplier,
            form.attackKnockback * knockbackMultiplier,
            breakObjects: true);
    }

    // ---- IAbility / IActiveAbility (Tarefa #34 — HUD) ----
    // Instantânea, sem estado persistente — só o cooldown importa para a HUD.
    void IAbility.Activate() => TryStrike();
    void IAbility.Release() { }
    public void Cancel(AbilityCancelReason reason) { }
    public float CooldownRemaining => Mathf.Max(0f, cooldownTimer);
    bool IAbility.IsActive => false;
    public float CooldownDuration => strikeCooldown;
    public bool CanActivate => enabledForForm && cooldownTimer <= 0f;

    /// <summary>AnimalsDebugPanel — zera o cooldown do golpe pesado.</summary>
    public void ResetCooldown() => cooldownTimer = 0f;
}
